mapper.sql:
SELECT T.ID, T.CATEGORY_ID, T.GOODS_SN, T.NAME, T.BRAND_ID, T.GOODS_NUMBER, T.KEYWORDS, T.GOODS_BRIEF, T.GOODS_DESC, T.IS_ON_SALE, T.ADD_TIME, T.SORT_ORDER, T.IS_DELETE, T.ATTRIBUTE_CATEGORY, T.COUNTER_PRICE, T.EXTRA_PRICE, T.IS_NEW, T.GOODS_UNIT, T.PRIMARY_PIC_URL, T.LIST_PIC_URL, T.RETAIL_PRICE, T.SELL_VOLUME, T.PRIMARY_PRODUCT_ID, T.UNIT_PRICE, T.PROMOTION_DESC, T.PROMOTION_TAG, T.APP_EXCLUSIVE_PRICE, T.IS_APP_EXCLUSIVE, T.IS_LIMITED, T.IS_HOT, T.MARKET_PRICE, T.CREATE_USER_ID, T.UPDATE_USER_ID, T.UPDATE_TIME, T.CREATE_USER_DEPT_ID FROM MALL_GOODS T WHERE 1=1
AND T.ID = #{params.id}
AND T.NAME LIKE '%${params.name}%'
AND T.CATEGORY_ID = #{params.categoryId}

mapper.select:
select a.id, a.name, a.list_pic_url, a.market_price, a.retail_price, a.goods_brief, b.id AS
product_id,count(og.id) as order_num
from mall_goods a
left join mall_product b on a.id = b.goods_id
left join mall_product c on a.id = c.goods_id and c.retail_price > b.retail_price and b.id != c.id
left join mall_order_goods og on og.product_id = b.id

    left join mall_goods_group gg on gg.goods_id = a.id

where 1 = 1 and b.id is not null and c.id is null and a.is_delete != 1

    and a.is_new = #{isNew}


    and a.is_hot = #{isHot}


    and a.brand_id = #{brandId}


    and a.name like concat('%',#{name},'%')


    and a.category_id = #{categoryId}


    and a.keywords like concat('%',#{keyword},'%')


    and gg.id is not null


    and a.category_id in

        #{item}



    and a.id in

        #{item}


group by a.id, a.name, a.list_pic_url, a.market_price, a.retail_price, a.goods_brief, b.id


        order by ${sidx} ${order}


        order by a.id desc



    limit #{offset}, #{limit}

